from flask import Flask, request, jsonify
from pymongo import MongoClient
from bson.json_util import dumps
import os
from werkzeug.security import generate_password_hash, check_password_hash
from flask_pymongo import PyMongo
from flask_cors import CORS
from dotenv import load_dotenv
import re

load_dotenv()

app = Flask(__name__)
CORS(app)

app.config["MONGO_URI"] = os.getenv("MONGO_URI", "mongodb://localhost:27017/cms")
mongo = PyMongo(app)

def validate_user_input(data):
    if not isinstance(data, dict):
        return False
    if 'username' not in data or not isinstance(data['username'], str) or not re.match("^[a-zA-Z0-9_]+$", data['username']):
        return False
    if 'email' not in data or not isinstance(data['email'], str) or not re.match(r"[^@]+@[^@]+\.[^@]+", data['email']):
        return False
    return True

@app.route('/register', methods=['POST'])
def register():
    data = request.json
    if not validate_user_input(data):
        return jsonify({"error": "Invalid input"}), 400
    
    hashed_password = generate_password_hash(data['password'])
    mongo.db.users.insert_one({
        "username": data['username'],
        "email": data['email'],
        "password": hashed_password
    })
    return jsonify({"message": "User registered successfully"}), 201

@app.route('/login', methods=['POST'])
def login():
    data = request.json
    user = mongo.db.users.find_one({"username": data['username']})
    if user and check_password_hash(user['password'], data['password']):
        return jsonify({"message": "Login successful"}), 200
    return jsonify({"error": "Invalid credentials"}), 401

@app.route('/profile/<username>', methods=['GET'])
def get_profile(username):
    user = mongo.db.users.find_one({"username": username})
    if user:
        user.pop('password')  # Do not expose password
        return jsonify(user), 200
    return jsonify({"error": "User not found"}), 404

@app.route('/aggregate', methods=['GET'])
def aggregate_profiles():
    pipeline = [
        {
            "$group": {
                "_id": "$email",
                "count": {"$sum": 1}
            }
        }
    ]
    result = mongo.db.users.aggregate(pipeline)
    return dumps(result), 200

if __name__ == '__main__':
    app.run(debug=False)